-  if (legacyState) {
-    return true;
-  }
-  const legacyCrypto = detectLegacyMatrixCrypto({ cfg: params.cfg, env });
-  return legacyCrypto.plans.length > 0 || legacyCrypto.warnings.length > 0;
-}
